@startuml
skinparam classAttributeIconSize 0

class ShoppingCart {
    <<entity>>
    /SubTotal : Currency
    /TaxAmount : Currency
    /DiscountAmount : Currency
    /TotalAmount : Currency
}

class ProductOnCart {
    <<entity>>
    /Price : Currency
    Quantity : Integer
    /Total : Currency
}

class Customer {
    C
}

class Product {
    C
}

' Relationships from original diagram - keeping exact multiplicities even if they seem unusual for standard domain modeling
ShoppingCart "1..1" --* "0..*" ProductOnCart : ProductsOnCart > 
ProductOnCart "0..*" --> "1..1" Product : Product > 

Customer <|--|> "1..1" ShoppingCart : Customer > ' Using bidirectional association to match visual arrows in both directions between these classes

@enduml
